inline std::optional<float> stringToFloat(const std::string& string) {
  try {
    size_t pos = 0;
    auto result = std::stof(string, &pos);
    // Check if entire string was valid
    if (pos == string.length()) {
      return result;
    }
  } catch (...) {
    // Ignore, caller falls back to default value.
    return std::nullopt;
  }

  return std::nullopt;
}

